   198	    private void addDeprecationWarning(Property property) throws IOException {
   199	        DeprecatedProperty strimziDeprecated = property.getAnnotation(DeprecatedProperty.class);
   200	        Deprecated langDeprecated = property.getAnnotation(Deprecated.class);
   201	
   202	        if (strimziDeprecated != null || langDeprecated != null) {
   203	            if (strimziDeprecated == null || langDeprecated == null) {
   204	                err(property + " must be annotated with both @" + Deprecated.class.getName()
   205	                        + " and @" + DeprecatedProperty.class.getName());
   206	            }
   207	            if (strimziDeprecated != null) {
   208	                out.append(getDeprecation(property, strimziDeprecated));
   209	            }
   210	        }
   211	    }
