   454	    public void typeLink(Crd crd, Appendable out, Class<?> cls) throws IOException {
   455	        if (short.class.equals(cls)
   456	                || Short.class.equals(cls)
   457	                || int.class.equals(cls)
   458	                || Integer.class.equals(cls)
   459	                || long.class.equals(cls)
   460	                || Long.class.equals(cls)) {
   461	            out.append("integer");
   462	        } else if (Float.class.equals(cls)
   463	                || float.class.equals(cls)
   464	                || Double.class.equals(cls)
   465	                || double.class.equals(cls)) {
   466	            out.append("number");
   467	        } else if (Object.class.equals(cls)
