   469	                || Map.class.equals(cls)
   470	                || Boolean.class.equals(cls)
   471	                || boolean.class.equals(cls)) {
   472	            out.append(cls.getSimpleName().toLowerCase(Locale.ENGLISH));
   473	        } else if (isPolymorphic(cls)) {
   474	            out.append(subtypes(crApiVersion, cls).stream().map(c -> {
