+/*
+ * Copyright Strimzi authors.
+ * License: Apache License 2.0 (see the file LICENSE or http://apache.org/licenses/LICENSE-2.0.html).
+ */
+package io.strimzi.crdgenerator.annotations;
+
+import java.lang.annotation.ElementType;
+import java.lang.annotation.Retention;
+import java.lang.annotation.RetentionPolicy;
+import java.lang.annotation.Target;
+
+/**
+ * Configure an external documentation URL to which we want to create a link.
+ */
+@Retention(RetentionPolicy.RUNTIME)
+@Target({ElementType.METHOD, ElementType.FIELD})
+public @interface ExternalLink {
+    /**
+     * Gets the external URL to which the link should point.
+     *
+     * @return  External URL to which the link should point
+     */
+    String value() default "";
+
+    /**
+     * Gets the external URL to which the link should point.
+     *
+     * @return  External URL to which the link should point
+     */
+    String url() default "";
+}
